sql:
SELECT SUM(total_amount) AS total_spent, AVG(total_amount) AS average_spent
FROM transactions
WHERE client_id = 0;

external_knowledge:
- 'Ventured into the market' refers to making transactions;
- 'Treasure trove of loyalty points' means high loyalty points;
- The metaphor 'dwarfs the total sum of their transactions when measured by its square root' indicates that the total transaction amount is less than the square root of the loyalty points.

- 'particular client' refers to client ID 100;
- 'specific store' refers to store ID 200;
- 'gadgets' refers to items in the 'Electronics' category.

- "shadows of returns" means transactions not marked as returns (is_return = 0);
- "rhythm of clients and their chosen merchandise" refers to the names of clients and items involved in transactions;
- "quantities they embrace" refers to the quantity of items sold;
- "hours when these dances occur" refers to the time of the transactions;
- "total whispers of trade" refers to the total amount of the transactions;
- "from the most recent to the distant past" indicates sorting by time in descending order;

sql:
SELECT DISTINCT e.employee_name 
FROM employees e
INNER JOIN transactions t ON e.employee_id = t.employee_id;

SELECT client_name, contact_number, email
FROM clients
WHERE loyalty_points > 2;

SELECT SUM(CAST(REPLACE(trim(total_amount, '$'), ',', '') AS REAL)) AS total_wealth
FROM transactions
WHERE client_id = (SELECT client_id FROM clients WHERE client_name = 'John Doe');

SELECT DISTINCT c.client_name 
FROM clients c 
INNER JOIN transactions t ON c.client_id = t.client_id;
